"""Сумма трёх синусоид."""from __future__ import annotationsimport numpy as npfrom .base import BaseSignal, _check_below_nyquist, _time_axisclass MultiSineSignal(BaseSignal):    name = "Сумма синусоид"    description = "Сумма трёх гармонических составляющих: Σ Aᵢ·sin(2π·fᵢ·t)."    params_schema = {        "amp1":     {"type": "float", "default": 1.00, "min": 0.0, "max": 1.0e6,                     "label": "Амплитуда 1", "units": "В"},        "freq1":    {"type": "float", "default": 10.0, "min": 1.0e-6, "max": 1.0e6,                     "label": "Частота 1", "units": "Гц"},        "amp2":     {"type": "float", "default": 0.50, "min": 0.0, "max": 1.0e6,                     "label": "Амплитуда 2", "units": "В"},        "freq2":    {"type": "float", "default": 50.0, "min": 1.0e-6, "max": 1.0e6,                     "label": "Частота 2", "units": "Гц"},        "amp3":     {"type": "float", "default": 0.25, "min": 0.0, "max": 1.0e6,                     "label": "Амплитуда 3", "units": "В"},        "freq3":    {"type": "float", "default": 120.0, "min": 1.0e-6, "max": 1.0e6,                     "label": "Частота 3", "units": "Гц"},        "duration": {"type": "float", "default": 1.0, "min": 1.0e-6, "max": 3600.0,                     "label": "Длительность", "units": "с"},        "fs":       {"type": "float", "default": 1000.0, "min": 1.0, "max": 1.0e6,                     "label": "Частота дискретизации", "units": "Гц"},    }    def _compute(self, p: dict) -> tuple[np.ndarray, np.ndarray]:        fs = p["fs"]        _check_below_nyquist("freq1", p["freq1"], fs)        _check_below_nyquist("freq2", p["freq2"], fs)        _check_below_nyquist("freq3", p["freq3"], fs)        t = _time_axis(p["duration"], fs)        two_pi = 2.0 * np.pi        x = (p["amp1"] * np.sin(two_pi * p["freq1"] * t)             + p["amp2"] * np.sin(two_pi * p["freq2"] * t)             + p["amp3"] * np.sin(two_pi * p["freq3"] * t))        return t, x